232	  const [step, setStep] = useState(0);
233	  const [fields, setFields] = useState<string[]>(
234	    Array.isArray(existingSurvey?.fields) ? existingSurvey.fields :
235	    existingSurvey?.field ? [existingSurvey.field] : []
236	  );
237	  const [descriptor, setDescriptor] = useState(existingSurvey?.descriptor || "");
238	  const [struggles, setStruggles] = useState<string[]>(existingSurvey?.struggles || []);
239	  const [experience, setExperience] = useState(existingSurvey?.experience || "");
240	  const [contentTypes, setContentTypes] = useState<string[]>(existingSurvey?.content_types || existingSurvey?.contentTypes || []);
241	  const [followerCount, setFollowerCount] = useState(existingSurvey?.follower_count || existingSurvey?.followerCount || "");
242	  const [monthlyRevenue, setMonthlyRevenue] = useState(existingSurvey?.monthly_revenue || existingSurvey?.monthlyRevenue || "");
243	  const [primaryGoal, setPrimaryGoal] = useState(existingSurvey?.primary_goal || existingSurvey?.primaryGoal || "");
244	  const [platforms, setPlatforms] = useState<string[]>(
245	    Array.isArray(existingSurvey?.platforms) ? existingSurvey.platforms :
246	    existingSurvey?.platform ? [existingSurvey.platform] : []
247	  );
248	  const [awareness, setAwareness] = useState(existingSurvey?.awareness || "");
249	  const [heardAbout, setHeardAbout] = useState<string[]>(
250	    Array.isArray(existingSurvey?.heard_about) ? existingSurvey.heard_about :
251	    Array.isArray(existingSurvey?.heardAbout) ? existingSurvey.heardAbout : []
252	  );
253	  const { toast } = useToast();
254	  const qc = useQueryClient();
255	
256	  const toggleItem = (arr: string[], setArr: (v: string[]) => void, item: string) => {
257	    setArr(arr.includes(item) ? arr.filter(x => x !== item) : [...arr, item]);
258	  };
259	
260	  const saveMutation = useMutation({
261	    mutationFn: () => apiRequest("POST", "/api/user/onboarding-survey", {
262	      field: fields.join(", "),
263	      fields,
264	      descriptor,
265	      struggles,
266	      experience,
267	      contentTypes,
268	      followerCount,
269	      monthlyRevenue,
270	      primaryGoal,
271	      platform: platforms.join(", "),
272	      platforms,
273	      awareness,
274	      heardAbout,
275	    }),
276	    onSuccess: () => {
277	      qc.invalidateQueries({ queryKey: ["/api/user/onboarding-status"] });
278	      onComplete();
279	    },
280	    onError: () => {
281	      toast({ title: "Something went wrong", description: "Please try again.", variant: "destructive" });
282	    },
283	  });
284	
285	  const canAdvance = () => {
286	    if (step === 0) return fields.length > 0;
