289	    if (step === 3) return !!experience;
290	    if (step === 4) return contentTypes.length > 0;
291	    if (step === 5) return !!followerCount;
292	    if (step === 6) return !!monthlyRevenue;
293	    if (step === 7) return !!primaryGoal;
294	    if (step === 8) return platforms.length > 0;
295	    if (step === 9) return !!awareness;
296	    if (step === 10) return heardAbout.length > 0;
297	    return false;
