4	export interface SurveyData {
5	  // Q0 — awareness level
6	  awareness: string;
7	  // Q1 — niche/field (primary + array)
8	  niche: string;
9	  fields: string[];
10	  // Q2 — struggles
11	  struggles: string[];
12	  topStruggle: string;
13	  // Q3 — content types
14	  contentTypes: string[];
15	  // Q4 — descriptor
16	  descriptor: string;
17	  // Q5 — experience
18	  experience: string;
19	  // Q6 — follower count
20	  followerCount: string;
21	  // Q7 — monthly revenue
22	  monthlyRevenue: string;
23	  // Q8 — primary goal
24	  primaryGoal: string;
25	  // Q9 — platforms
26	  platforms: string[];
27	  primaryPlatform: string;
28	  // Q10 — heard about
29	  heardAbout: string[];
30	  // Derived helpers
31	  isBeginnerLevel: boolean;
32	  isMonetised: boolean;
33	  preferShortForm: boolean;
34	  preferLongForm: boolean;
35	  goalLabel: string;
36	  hasData: boolean;
37	}
38	
39	const GOAL_LABEL_MAP: Record<string, string> = {
40	  "Grow my audience fast": "grow",
41	  "Land brand deals & sponsorships": "leads",
42	  "Sell digital products or courses": "sales",
43	  "Replace my 9–5 income": "sales",
44	  "Build a loyal community": "community",
45	  "Become a full-time content creator": "authority",
46	  "All of the above": "grow",
47	};
48	
49	const PLATFORM_NORM: Record<string, string> = {
50	  "Instagram": "instagram",
51	  "YouTube": "youtube",
52	  "TikTok": "tiktok",
53	  "LinkedIn": "linkedin",
54	  "Twitter / X": "twitter",
55	  "Pinterest": "pinterest",
56	  "Threads": "threads",
57	  "Facebook": "facebook",
58	};
59	
60	export function useSurvey(): SurveyData {
61	  const { user } = useAuth();
62	  const u = user as any;
63	
64	  const { data: surveyData } = useQuery<any>({
65	    queryKey: ["/api/user/onboarding-status"],
66	    enabled: !!u?.id,
67	    staleTime: Infinity,
68	  });
69	
70	  const survey = surveyData?.survey;
71	
72	  // Pull from user object (already merged by server) or raw survey
73	  const fields: string[] = u?.fields || survey?.fields || [];
74	  const struggles: string[] = u?.struggles || survey?.struggles || [];
75	  const contentTypes: string[] = u?.contentTypes || survey?.content_types || [];
76	  const platforms: string[] = u?.platforms || survey?.platforms || [];
77	  const heardAbout: string[] = u?.heardAbout || survey?.heard_about || [];
78	
79	  const niche = fields.length > 0 ? fields[0] : "";
80	  const topStruggle = struggles[0] || "";
81	  const primaryPlatform = platforms.length > 0
82	    ? (PLATFORM_NORM[platforms[0]] || platforms[0].toLowerCase())
83	    : "instagram";
84	
85	  const awareness: string = u?.awareness || survey?.awareness || "";
86	  const descriptor: string = u?.descriptor || survey?.descriptor || "";
87	  const experience: string = u?.experience || survey?.experience || "";
88	  const followerCount: string = u?.followerCount || survey?.follower_count || "";
89	  const monthlyRevenue: string = u?.monthlyRevenue || survey?.monthly_revenue || "";
90	  const primaryGoal: string = u?.primaryGoal || survey?.primary_goal || "";
91	
92	  const isBeginnerLevel =
93	    awareness.includes("beginner") ||
94	    awareness.includes("basics") ||
95	    experience.includes("less than 1 month") ||
96	    experience.includes("Less than 6 months");
97	
98	  const isMonetised = !monthlyRevenue.includes("$0") && monthlyRevenue !== "";
99	
100	  const preferShortForm = contentTypes.some(c =>
101	    c.toLowerCase().includes("short") || c.toLowerCase().includes("reel") || c.toLowerCase().includes("tiktok")
102	  );
103	
104	  const preferLongForm = contentTypes.some(c =>
105	    c.toLowerCase().includes("long") || c.toLowerCase().includes("youtube") || c.toLowerCase().includes("podcast")
106	  );
107	
108	  const goalLabel = GOAL_LABEL_MAP[primaryGoal] || "grow";
109	
110	  const hasData = fields.length > 0 || struggles.length > 0 || !!primaryGoal;
111	
112	  return {
113	    awareness,
114	    niche,
115	    fields,
116	    struggles,
117	    topStruggle,
118	    contentTypes,
119	    descriptor,
120	    experience,
121	    followerCount,
122	    monthlyRevenue,
123	    primaryGoal,
124	    platforms,
125	    primaryPlatform,
126	    heardAbout,
127	    isBeginnerLevel,
128	    isMonetised,
129	    preferShortForm,
130	    preferLongForm,
131	    goalLabel,
132	    hasData,
133	  };
134	}
