17	export default function UpgradeModal() {
18	  const [open, setOpen] = useState(false);
19	  const [detail, setDetail] = useState<any>(null);
20	  const [, navigate] = useLocation();
21	  const { user } = useAuth();
22	
23	  useEffect(() => {
24	    const handler = (e: Event) => {
25	      setDetail((e as CustomEvent).detail);
26	      setOpen(true);
