36	  const nextColor = nextPlan ? getPlanColor(nextPlan) : GOLD;
37	  const perks = nextPlan ? (UPGRADE_PERKS[nextPlan] ?? []) : [];
38	  const currentTotal = detail?.balance
39	    ? (detail.balance.monthlyCredits ?? 0) + (detail.balance.bonusCredits ?? 0)
40	    : 0;
41	
42	  return (
43	    <Dialog open={open} onOpenChange={setOpen}>
44	      <DialogContent className="max-w-md border border-zinc-800 bg-zinc-950 text-white p-0 overflow-hidden">
