54	              </div>
55	            </div>
56	          </DialogHeader>
57	
58	          {detail?.message && (
59	            <p className="text-sm text-zinc-400 leading-relaxed">{detail.message}</p>
60	          )}
61	        </div>
62	
63	        <div className="px-6 py-5 space-y-4">
64	          {nextPlan ? (
65	            <>
66	              <div className="rounded-xl border p-4 space-y-3" style={{ borderColor: `${nextColor}30`, background: `${nextColor}08` }}>
67	                <div className="flex items-center justify-between">
