95	          )}
96	
97	          <Button
98	            variant="outline"
99	            className="w-full font-medium text-sm h-10 border-zinc-700 text-zinc-300 hover:bg-zinc-800"
100	            onClick={() => { setOpen(false); navigate("/credits"); }}
